import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int gcd = A[0];
            for (int i = 1; i < N; i++) {
                gcd = gcd(gcd, A[i]);
            }
            if (gcd == 1) {
                System.out.println("YES");
            } else {
                int found = 0;
                for (int i = 0; i < N; i++) {
                    for (int j = 2; j * j <= A[i]; j++) {
                        if (A[i] % j == 0 && j <= K) {
                            found = 1;
                            break;
                        }
                    }
                    if (found > 0) break;
                }
                if (found > 0) {
                    System.out.println("YES");
                } else {
                    System.out.println("NO");
                }
            }
        }
    }
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}

